import { Component, Input, Output, EventEmitter } from '@angular/core';

@Component({
  selector: 'app-info-alert',
  templateUrl: './info-alert.component.html',
  styleUrls: ['./info-alert.component.css']
})
export class InfoAlertComponent {
  @Input()
  styleToInsert: string = "";

  @Input()
  message: string = "";

  @Output()
  statusCode = new EventEmitter<null>();

  onClose(): void {
    this.statusCode.emit(null);
  }
}
<div class="p-3 bg-dark bg-gradient border border-3 border-warning rounded-3">
    <div class="row">
        <div class="col-12 col-md-9 ms-md-3 pt-2" [ngClass]="styleToInsert">{{message}}</div>
        <div class="col-12 col-md-1 pt-1">
            <button class="btn-close ms-md-1 ms-lg-4 ms-xl-5" (click)="onClose()"></button>
        </div>
    </div>
</div>
